function Tably(selector){this.container=document.querySelector(selector);if(!this.container){console.error(`${selector} does not exist`);return}this.tabs=Array.from(this.container.querySelectorAll("li a"));if(!this.tabs.length){console.error(`No tabs found in ${selector}`);return}this.panels=this.tabs.map(tab=>{const panel=document.querySelector(tab.getAttribute("href"));if(!panel){console.error(`Panel ${tab.getAttribute("href")} does not exist`)}return panel});if(this.panels.includes(null))return;this._init()}Tably.prototype._init=function(){this._activateTab(this.tabs[0]);this._bondTabEvents=this._handleTabClick.bind(this);this.tabs.forEach(tab=>{tab.addEventListener("click",this._bondTabEvents)})};Tably.prototype._handleTabClick=function(e){e.preventDefault();this._activateTab(e.currentTarget)};Tably.prototype.removeEvents=function(){this.tabs.forEach(tab=>{tab.removeEventListener("click",this._bondTabEvents)})};Tably.prototype._activateTab=function(tab){this.tabs.forEach(tab=>tab.closest("li").classList.remove("tably--active"));tab.closest("li").classList.add("tably--active");this.panels.forEach(panel=>panel.hidden=true);const targetPanel=document.querySelector(tab.getAttribute("href"));if(targetPanel){targetPanel.hidden=false}};Tably.prototype.switch=function(input){let targetTab=null;if(typeof input==="string"){targetTab=this.tabs.find(tab=>tab.getAttribute("href")===input);if(targetTab){this._activateTab(targetTab)}else{console.error(`Tab with input "${input}" does not exist`);return}}else if(this.tabs.includes(input)){targetTab=input}if(!targetTab){console.error(`Tab with input "${input}" does not exist`);return}this._activateTab(targetTab)};Tably.prototype.destroy=function(){this.removeEvents();this.tabs.forEach(tab=>{tab.closest("li").classList.remove("tably--active")});this.panels.forEach(panel=>panel.hidden=false);this.container=null;this.tabs=null;this.panels=null};